@namespace Lumeo

@{
    var context = new ListContext(Bordered, Hoverable, Size);
}

<CascadingValue Value="context" IsFixed="false">
    <ul role="list" class="@CssClass" @attributes="AdditionalAttributes">
        @ChildContent
    </ul>
</CascadingValue>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public bool Bordered { get; set; }
    [Parameter] public bool Hoverable { get; set; }
    [Parameter] public Lumeo.Size Size { get; set; } = Lumeo.Size.Md;
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge(
        "w-full",
        Cx.When(Bordered, "divide-y divide-border/40 rounded-md border border-border/40"),
        Class);

    public record ListContext(bool Bordered, bool Hoverable, Lumeo.Size Size);

}

@namespace Lumeo

@{
    // Row padding keyed on List Size x ambient DensityScope; Comfortable
    // reproduces the historical per-Size padding verbatim.
    var paddingClass = (Context?.Size ?? Lumeo.Size.Md, Density ?? Lumeo.Density.Comfortable) switch
    {
        (Lumeo.Size.Sm, Lumeo.Density.Compact)  => "px-2.5 py-1.5",
        (Lumeo.Size.Sm, Lumeo.Density.Spacious) => "px-4 py-3",
        (Lumeo.Size.Sm, _)                      => "px-3 py-2",
        (Lumeo.Size.Lg, Lumeo.Density.Compact)  => "px-4 py-3",
        (Lumeo.Size.Lg, Lumeo.Density.Spacious) => "px-6 py-5",
        (Lumeo.Size.Lg, _)                      => "px-5 py-4",
        (_, Lumeo.Density.Compact)              => "px-3 py-2",
        (_, Lumeo.Density.Spacious)             => "px-5 py-4",
        _                                       => "px-4 py-3"
    };
    var hoverClass = Context?.Hoverable == true ? "hover:bg-accent/50 transition-colors" : "";
    var clickableClass = (OnClick.HasDelegate || !string.IsNullOrEmpty(Href)) ? "cursor-pointer" : "";
    var disabledClass = Disabled ? "opacity-50 pointer-events-none" : "";
    var liClass = Cx.Merge("flex items-center gap-3", paddingClass, hoverClass, clickableClass, disabledClass, Class);
}

@if (!string.IsNullOrEmpty(Href))
{
    <li class="@liClass" @attributes="AdditionalAttributes">
        @* OnClick fires alongside navigation — no preventDefault, both work. *@
        <a href="@Href" class="flex flex-1 items-center gap-3 min-w-0" @onclick="HandleClick">
            @if (Leading != null)
            {
                <div class="shrink-0">@Leading</div>
            }
            <div class="flex-1 min-w-0">
                @if (Title != null)
                {
                    <p class="text-sm font-medium truncate">@Title</p>
                }
                @if (Description != null)
                {
                    <p class="text-xs text-muted-foreground truncate">@Description</p>
                }
                @ChildContent
            </div>
        </a>
        @if (Trailing != null)
        {
            <div class="shrink-0">@Trailing</div>
        }
    </li>
}
else
{
    <li class="@liClass"
        role="@(OnClick.HasDelegate ? "button" : null)"
        tabindex="@(OnClick.HasDelegate && !Disabled ? "0" : null)"
        @onclick="HandleClick"
        @onkeydown="HandleKeyDown"
        @attributes="AdditionalAttributes">
        @if (Leading != null)
        {
            <div class="shrink-0">@Leading</div>
        }
        <div class="flex-1 min-w-0">
            @if (Title != null)
            {
                <p class="text-sm font-medium truncate">@Title</p>
            }
            @if (Description != null)
            {
                <p class="text-xs text-muted-foreground truncate">@Description</p>
            }
            @ChildContent
        </div>
        @if (Trailing != null)
        {
            <div class="shrink-0">@Trailing</div>
        }
    </li>
}

@code {
    [CascadingParameter] public List.ListContext? Context { get; set; }
    [CascadingParameter] private Lumeo.Density? Density { get; set; }

    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public RenderFragment? Leading { get; set; }
    [Parameter] public RenderFragment? Trailing { get; set; }
    [Parameter] public string? Title { get; set; }
    [Parameter] public string? Description { get; set; }
    [Parameter] public string? Href { get; set; }
    [Parameter] public EventCallback OnClick { get; set; }
    [Parameter] public bool Disabled { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private async Task HandleClick()
    {
        if (!Disabled && OnClick.HasDelegate)
            await OnClick.InvokeAsync();
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (Disabled || !OnClick.HasDelegate) return;
        if (e.Key is "Enter" or " ") await OnClick.InvokeAsync();
    }
}
